INSERT INTO pending_submissions (id, level_id, level_name, is_new_level, record_data, level_data, submitted_at, submitted_by, status) VALUES ('pending-1772950659685-n1gv1lm04', '126242564', 'Flamewall', 1, '{"player":"ibeatflamewalllol","date":"26/03/08","cbf":false,"videoUrl":"www"}', '{"levelId":"126242564","name":"Flamewall","hkgdRank":2,"aredlRank":2,"pemonlistRank":null,"creator":"Narwall","verifier":"[400] CuatrocientosYT","description":"Over seven minutes of extremely fast and challenging gameplay, using a similarly very fast and dramatic symphonic metal song, and featuring very few break sections for its length. Features a gargantuan roster of creators and took multiple years to come out, in part thanks to the verifier dying at 99% twice.","songName":"Flamewall by Camellia","songId":"10007151","thumbnail":"https://levelthumbs.prevter.me/thumbnail/126242564","tags":["XXL+","2.2","Nerve Control","Fast-Paced","Overall"]}', '26/03/08', 'ibeatflamewalllol', 'rejected');
